using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap a REST API using constructor-injected HttpClient.
/// The SDK resolves DI services (HttpClient, ILogger) automatically —
/// they never appear in the tool schema exposed to the LLM.
/// </summary>
[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions JsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("List all users from the REST API.")]
    public async Task<string> ListUsers(
        [Description("Maximum number of results to return (1–100).")] int limit = 10,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Listing users (limit={Limit})", limit);
        var users = await httpClient.GetFromJsonAsync<JsonElement>(
            $"/users?_limit={limit}", cancellationToken);
        return JsonSerializer.Serialize(users, JsonOptions);
    }

    [McpServerTool, Description("Get a single user by their numeric ID.")]
    public async Task<string> GetUser(
        [Description("The numeric user ID.")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching user {Id}", id);
        var response = await httpClient.GetAsync($"/users/{id}", cancellationToken);

        if (!response.IsSuccessStatusCode)
            return $"Error: API returned {(int)response.StatusCode} {response.ReasonPhrase}";

        var user = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(user, JsonOptions);
    }

    [McpServerTool, Description("Create a new user via the REST API.")]
    public async Task<string> CreateUser(
        [Description("The user's full name.")] string name,
        [Description("The user's email address.")] string email,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Creating user {Name}", name);
        var payload = new { name, email };
        var response = await httpClient.PostAsJsonAsync("/users", payload, cancellationToken);
        var body = await response.Content.ReadFromJsonAsync<JsonElement>(cancellationToken);
        return JsonSerializer.Serialize(body, JsonOptions);
    }
}

